// ─── helpers ───
async function ensureDemoOrg() {
  const { data: existing } = await supabase
    .from("orgs")
    .select("id")
    .eq("name", DEMO_ORG_NAME)
    .maybeSingle();
  if (existing) return existing.id;
  const { data: created, error } = await supabase
    .from("orgs")
    .insert({ name: DEMO_ORG_NAME, is_demo: true })
    .select("id")
    .single();
  if (error) throw new Error(`Could not create demo org: ${error.message}`);
  return created.id;
}

async function findUserByEmail(email) {
  // No direct getUserByEmail in supabase-js v2's admin API — page through
  // listUsers. Fine at demo scale (a handful of users on this project).
  let page = 1;
  for (;;) {
    const { data, error } = await supabase.auth.admin.listUsers({ page, perPage: 200 });
    if (error) throw new Error(`listUsers failed: ${error.message}`);
    const found = data.users.find((u) => u.email === email);
    if (found) return found;
    if (data.users.length < 200) return null;
    page++;
  }
}

async function ensureExpertUser(expert) {
  let user = await findUserByEmail(expert.email);
  if (!user) {
    const { data, error } = await supabase.auth.admin.createUser({
      email: expert.email,
      password: DEMO_PASSWORD,
      email_confirm: true,
    });
    if (error) throw new Error(`createUser(${expert.email}) failed: ${error.message}`);
    user = data.user;
  }
  return user;
}

async function waitForProfile(userId) {
  // handle_new_user() trigger fires async-ish on insert into auth.users;
  // give it a few tries before giving up.
  for (let i = 0; i < 10; i++) {
    const { data } = await supabase.from("profiles").select("id").eq("id", userId).maybeSingle();
    if (data) return;
    await new Promise((r) => setTimeout(r, 500));
  }
  throw new Error(`profiles row never appeared for user ${userId}`);
}

async function main() {
  console.log(`Demo org: "${DEMO_ORG_NAME}"`);
  const orgId = await ensureDemoOrg();
  console.log(`  org_id = ${orgId}`);

  const expertIds = {};
  for (const expert of EXPERTS) {
    const user = await ensureExpertUser(expert);
    await waitForProfile(user.id);
    const { error } = await supabase
      .from("profiles")
      .update({
        org_id: orgId,
        persona: expert.persona,
        display_name: expert.display_name,
        updated_at: new Date().toISOString(),
      })
      .eq("id", user.id);
    if (error) throw new Error(`profile update failed for ${expert.email}: ${error.message}`);
    expertIds[expert.key] = user.id;
    console.log(`  ${expert.display_name} (${expert.persona}) → ${user.id}`);
  }

  const { count: existingCount } = await supabase
    .from("pattern_records")
    .select("id", { count: "exact", head: true })
    .eq("org_id", orgId);

  if (existingCount >= RECORDS.length && !FORCE) {
    console.log(
      `Demo org already has ${existingCount} pattern_records (expected ${RECORDS.length}) — skipping seed. Pass --force to reseed.`
    );
    console.log(`\nLogin for any seeded expert: <their email> / ${DEMO_PASSWORD}`);
    return;
  }

  if (FORCE && existingCount > 0) {
    console.log(`--force: deleting ${existingCount} existing demo pattern_records for this org...`);
    const { error } = await supabase.from("pattern_records").delete().eq("org_id", orgId);
    if (error) throw new Error(`delete failed: ${error.message}`);
  }

  const now = Date.now();
  let inserted = 0;
  for (const rec of RECORDS) {
    const userId = expertIds[rec.expert];
    const fields = {
      context_summary: rec.context_summary,
      context_org_size: rec.context_org_size,
      context_industry: "Manufacturing",
      context_function: rec.context_function,
      situation_type: rec.situation_type,
      intervention_type: rec.intervention_type,
      trigger_signal: rec.trigger_signal,
      signal_detail: rec.signal_detail,
      judgment: rec.judgment,
      rationale: rec.rationale,
      boundaries: rec.boundaries,
      entity_map: rec.entity_map,
    };

    console.log(`Framing "${fields.context_summary.slice(0, 60)}..." (${rec.expert}, ${rec.trigger_type}/${rec.method})`);
    const framework = await framePattern(fields);
    if (!framework) {
      console.error(`  ⚠️ framePattern failed after retries — skipping this record`);
      continue;
    }

    const sessionStart = new Date(now - rec.daysAgo * 24 * 60 * 60 * 1000);
    // Time-to-first-value: a plausible 6-14 minute session, varied per record
    // rather than identical, so P-4.5/analytics don't see a suspicious constant.
    const ttfvSeconds = 360 + (rec.daysAgo % 7) * 90;
    const framedAt = new Date(sessionStart.getTime() + ttfvSeconds * 1000);
    const qaPairs = buildQaPairs(fields, rec.method);

    const { error } = await supabase.from("pattern_records").insert({
      user_id: userId,
      qa_pairs: qaPairs,
      pending_question: null,
      pending_rung: null,
      status: "complete",
      trigger_type: rec.trigger_type,
      method: rec.method,
      scrub_status: "not_scrubbed_by_design",
      ...fields,
      framework,
      session_start: sessionStart.toISOString(),
      framework_rendered_at: framedAt.toISOString(),
      time_to_first_value_seconds: ttfvSeconds,
      created_at: sessionStart.toISOString(),
      updated_at: framedAt.toISOString(),
    });
    if (error) {
      console.error(`  ⚠️ insert failed: ${error.message}`);
      continue;
    }
    inserted++;
    console.log(`  ✓ "${framework.name}"`);
  }

  console.log(`\nSeeded ${inserted}/${RECORDS.length} pattern_records for ${DEMO_ORG_NAME}.`);
  console.log(`Login for any seeded expert: <their email> / ${DEMO_PASSWORD}`);
  console.log(`Experts: ${EXPERTS.map((e) => `${e.display_name} <${e.email}>`).join(", ")}`);
  console.log(
    `Corroboration clusters to check in the library / P-4.5 later: "Marcus Webb" (win records — Elena, Tom, Angela), "Denise Ortiz" (win records — David, Priya).`
  );
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
